export function ErrorBoundary({ error }: Route.ErrorBoundaryProps) {
  const rollbar = getRollbar();

  let message = "Oops!";
  let details = "An unexpected error occurred.";
  let stack: string | undefined;

  if (shouldReload(error)) {
    window.location.reload();
    return;
  }

  if (error instanceof Error) {
    rollbar.error(error);
  } else if (typeof error === "object") {
    rollbar.error(new Error(JSON.stringify(error)));
  } else {
    rollbar.error(new Error(String(error)));
  }

  if (isRouteErrorResponse(error)) {
    message = error.status === 404 ? "404" : "Error";
    details =
      error.status === 404
        ? "The requested page could not be found."
        : error.statusText || details;
  } else if (import.meta.env.DEV && error && error instanceof Error) {
    details = error.message;
    stack = error.stack;
  }

  return (
    <main className="container mx-auto p-4 pt-16">
      <h1>{message}</h1>
      <p>{details}</p>
      {stack && (
        <pre className="w-full overflow-x-auto p-4">
          <code>{stack}</code>
        </pre>
      )}
    </main>
  );
}

function shouldReload(error: unknown) {
  if (error instanceof Error) {
    if (
      error.name === "TypeError" &&
      /Failed to fetch|NetworkError when attempting to fetch resource|Load failed/i.test(
        error.message,
      )
    ) {
      return true;
    }

    if (error.message.includes("Unable to decode turbo-stream response")) {
      return true;
    }
  }

  return false;
}

