import Rollbar from "rollbar";

export default function getRollbar() {
  const accessToken =
    typeof window === "undefined"
      ? process.env["ROLLBAR_SERVER_ACCESS_TOKEN"]
      : import.meta.env["VITE_ROLLBAR_CLIENT_ACCESS_TOKEN"];

  if (!accessToken) {
    if (typeof window === "undefined") {
      throw new Error("ROLLBAR_SERVER_ACCESS_TOKEN is not set");
    }

    throw new Error("VITE_ROLLBAR_CLIENT_ACCESS_TOKEN is not set");
  }

  if (import.meta.env.MODE === "production") {
    return new Rollbar({
      accessToken,
      captureUncaught: true,
      captureUnhandledRejections: true,
      payload: {
        environment:
          typeof window === "undefined"
            ? process.env["VITE_VIP_BASE_URI"]
            : window.location.origin,
        context: typeof window === "undefined" ? "server" : "client",
      },
      replay: {
        enabled: false,
      },
    });
  }

  return console;
}
